@startuml

class AbstractFactoryPatternDemo <<C>> {
  void main()
}

class FactoryProducer <<C>> {
  AbstractFactory getFactory()
}

abstract class AbstractFactory <<A>> {
  Shape getShape()
  Color getColor()
}

class ShapeFactory <<C>> {
  Shape getShape()
}

class ColorFactory <<C>> {
  Color getColor()
}

interface Shape <<I>> {
  void draw()
}

interface Color <<I>> {
  void fill()
}

class Circle <<C>> {
  void draw()
}

class Rectangle <<C>> {
  void draw()
}

class Square <<C>> {
  void draw()
}

class Blue <<C>> {
  void fill()
}

class Green <<C>> {
  void fill()
}

class Red <<C>> {
  void fill()
}

AbstractFactoryPatternDemo --> FactoryProducer : ask
FactoryProducer --> AbstractFactory : make

ShapeFactory --|> AbstractFactory : extends
ColorFactory --|> AbstractFactory : extends

Circle ..|> Shape : implement
Rectangle ..|> Shape : implement
Square ..|> Shape : implement

Blue ..|> Color : implement
Green ..|> Color : implement
Red ..|> Color : implement

ShapeFactory --> Shape : create
ColorFactory --> Color : create

package "shape" {
  Shape
  Circle
  Rectangle
  Square
}

package "color" {
  Color
  Blue
  Green
  Red
}

@enduml
